mapper.select:
select * from product


        and name like concat('%', #{params.name}, '%')


        and category_id = #{params.categoryId}


        and status = #{params.status}


order by create_time desc

mapper.update:
update product
name = #{name}, description = #{description}, price = #{price}, stock = #{stock}, sales = #{sales}, category_id = #{categoryId}, status = #{status}, tag = #{tag}, image = #{image}, update_time = #{updateTime}, update_user = #{updateUser},
where id = #{id}
